run(function()
    local InvisibleCursor = {}
    local isActive = false
    local renderConnection
    local ViewMode = {Value = 'First Person'}
    local LimitToItems = {Enabled = false}
    local ShowOnGUI = {Enabled = false}
    local lastCursorState = nil
    
    local function hasBowEquipped()
        if not store.hand or not store.hand.tool then
            return false
        end
        
        local toolName = store.hand.tool.Name:lower()
        return toolName:find('bow') ~= nil or toolName:find('crossbow') ~= nil
    end
    
    local function shouldHideCursor()
        if not isActive then return false end
        
        if ShowOnGUI.Enabled and isGUIOpen() then
            return false
        end
        
        if LimitToItems.Enabled and not hasBowEquipped() then
            return false
        end
        
        local inFirstPerson = isFirstPerson()
    
        if ViewMode.Value == 'First Person' then
            return inFirstPerson
        elseif ViewMode.Value == 'Third Person' then
            return not inFirstPerson
        elseif ViewMode.Value == 'Both' then
            return true
        end
        
        return false
    end
    
    local function updateCursor()
        local shouldHide = shouldHideCursor()
        
        if lastCursorState == shouldHide then
            return 
        end
        
        lastCursorState = shouldHide
        inputService.MouseIconEnabled = not shouldHide
    end
    
    InvisibleCursor = vape.Categories.Utility:CreateModule({
        Name = 'InvisibleCursor',
        Function = function(callback)
            if callback then
                isActive = true
                lastCursorState = nil
                
                if renderConnection then
                    renderConnection:Disconnect()
                end
                
				local invisFrameCounter = 0
				renderConnection = runService.Heartbeat:Connect(function()
					invisFrameCounter = invisFrameCounter + 1
					if invisFrameCounter % 10 ~= 0 then return end
					updateCursor()
				end)
				InvisibleCursor:Clean(renderConnection)

				InvisibleCursor:Clean(vapeEvents.InventoryChanged.Event:Connect(updateCursor))
            else
                isActive = false
                
                if renderConnection then
                    renderConnection:Disconnect()
                    renderConnection = nil
                end
                
                inputService.MouseIconEnabled = true
                lastCursorState = nil
            end
        end,
        Tooltip = 'Hides cursor based on view mode and item settings'
    })
    
    ViewMode = InvisibleCursor:CreateDropdown({
        Name = 'View Mode',
        List = {'First Person', 'Third Person', 'Both'},
        Default = 'First Person',
        Tooltip = 'Choose when to hide cursor\nFirst Person: Only in 1st person\nThird Person: Only in 3rd person\nBoth: Always hide',
        Function = function(val)
            ViewMode.Value = val
            updateCursor()
        end
    })
    
    LimitToItems = InvisibleCursor:CreateToggle({
        Name = 'Limit to Bow',
        Default = false,
        Tooltip = 'Only hide cursor when holding a bow/crossbow',
        Function = function(val)
            LimitToItems.Enabled = val
            updateCursor()
        end
    })
    
    ShowOnGUI = InvisibleCursor:CreateToggle({
        Name = 'Show on GUI',
        Default = false,
        Tooltip = 'Show cursor when any GUI is open (inventory, shop, etc)',
        Function = function(val)
            ShowOnGUI.Enabled = val
            updateCursor()
        end
    })
end)

run(function()
    local LootTP
    local Height
    local Network
    local FrozenItems = {}
    local EnabledTime = 0
    
    LootTP = vape.Categories.Utility:CreateModule({
        Name = 'LootTP',
        Function = function(callback)
            if callback then
                EnabledTime = tick()
                local items = collection('ItemDrop', LootTP)
                repeat
                    if entitylib.isAlive then
                        local localPosition = entitylib.character.HumanoidRootPart.Position
                        
                        for _, v in items do
                            local dropTime = v:GetAttribute('ClientDropTime') or 0
                            
                            -- Only process items dropped AFTER module was enabled
                            if dropTime >= EnabledTime then
                                if isnetworkowner(v) and Network.Enabled and entitylib.character.Humanoid.Health > 0 then
                                    -- Teleport item to frozen height immediately
                                    if not FrozenItems[v] then
                                        local voidHeight = Height.Value
                                        local targetPosition = Vector3.new(v.Position.X, voidHeight, v.Position.Z)
                                        
                                        v.CFrame = CFrame.new(targetPosition)
                                        v.AssemblyLinearVelocity = Vector3.new(0, 0, 0)
                                        
                                        FrozenItems[v] = targetPosition
                                    else
                                        -- Keep item frozen at height
                                        v.CFrame = CFrame.new(FrozenItems[v])
                                        v.AssemblyLinearVelocity = Vector3.new(0, 0, 0)
                                    end
                                end
                            end
                        end
                    end
                    task.wait(0.1)
                until not LootTP.Enabled
                
                -- When disabled, teleport all frozen items to player and pick them up
                if entitylib.isAlive then
                    for item, _ in pairs(FrozenItems) do
                        if item and item.Parent then
                            task.spawn(function()
                                local playerHumanoid = entitylib.character.HumanoidRootPart
                                if playerHumanoid then
                                    item.CFrame = CFrame.new(playerHumanoid.Position)
                                end
                                
                                task.wait(0.05)
                                
                                bedwars.Client:Get(remotes.PickupItem):CallServerAsync({
                                    itemDrop = item
                                }):andThen(function(suc)
                                    if suc and bedwars.SoundList then
                                        bedwars.SoundManager:playSound(bedwars.SoundList.PICKUP_ITEM_DROP)
                                        local sound = bedwars.ItemMeta[item.Name].pickUpOverlaySound
                                        if sound then
                                            bedwars.SoundManager:playSound(sound, {
                                                position = item.Position,
                                                volumeMultiplier = 0.9
                                            })
                                        end
                                    end
                                end)
                            end)
                        end
                    end
                end
                
                FrozenItems = {}
            end
        end,
        Tooltip = 'Freezes dropped items at set height, teleports to you when disabled'
    })
    
    Height = LootTP:CreateSlider({
        Name = 'Void Height',
        Min = -500,
        Max = -50,
        Default = -200,
        Suffix = function(val) 
            return val == 1 and 'stud' or 'studs' 
        end
    })
    
    Network = LootTP:CreateToggle({
        Name = 'Network TP',
        Default = true
    })
end)
	
