run(function()
    local aim = 0.158
    local tnt = 0.0045
    local aunchself = 0.395

    local defaultaim = 0.4
    local defaulttnt = 0.2
    local defaultself = 0.4

	local A
	local T
	local L
	local C
	local AJ
	local AS

    local function setCannonSpeeds(blocksFolder, aimDur, tntDur, selfDur)
        for _, v in ipairs(blocksFolder:GetChildren()) do 
            if v:IsA("BasePart") and v.Name == "cannon" then
                local AimPrompt = v:FindFirstChild("AimPrompt")
                local FirePrompt = v:FindFirstChild("FirePrompt")
                local LaunchSelfPrompt = v:FindFirstChild("LaunchSelfPrompt")
                if AimPrompt and FirePrompt and LaunchSelfPrompt then
                    AimPrompt.HoldDuration = aimDur
                    FirePrompt.HoldDuration = tntDur
                    LaunchSelfPrompt.HoldDuration = selfDur
                end
            end
        end
    end

    BetterDavey = vape.Categories.Kits:CreateModule({
        Name = "BetterDavey",
        Tooltip = "makes u look better with davey makes u play like me(i main davey everyday kush)",
		Function = function(callback)
			local worldFolder = getWorldFolder()
			if not worldFolder then return end
			local blocks = worldFolder:WaitForChild("Blocks")
			if callback then
				setCannonSpeeds(blocks, aim, tnt, aunchself)

				local function onLaunchTriggered(child)
					local humanoid = entitylib.character.Humanoid
					if not humanoid then return end
					if Speed.Enabled and Fly.Enabled then
						Fly:Toggle(false)
						task.wait(0.025)
						Speed:Toggle(false)
					elseif Speed.Enabled then
						Speed:Toggle(false)
					elseif Fly.Enabled then
						Fly:Toggle(false)
					end
					if AS.Enabled then
						local pickaxe = getPickaxeSlot()
						if hotbarSwitch(pickaxe) or store.hand.tool.Name:lower():find("pickaxe") then
							task.spawn(bedwars.breakBlock, child, false, nil, true)
							task.spawn(bedwars.breakBlock, child, false, nil, true)
						end
					else
						task.spawn(bedwars.breakBlock, child, false, nil, true)
						task.spawn(bedwars.breakBlock, child, false, nil, true)
					end
					if AJ.Enabled then
						if humanoid:GetState() ~= Enum.HumanoidStateType.Jumping then
							humanoid:ChangeState(Enum.HumanoidStateType.Jumping)
						end
					end
				end

				local function setupCannon(child)
					if not (child:IsA("BasePart") and child.Name == "cannon" and BetterDavey.Enabled) then return end
					local AimPrompt = child:WaitForChild("AimPrompt")
					local FirePrompt = child:WaitForChild("FirePrompt")
					local LaunchSelfPrompt = child:WaitForChild("LaunchSelfPrompt")
					AimPrompt.HoldDuration = aim
					FirePrompt.HoldDuration = tnt
					LaunchSelfPrompt.HoldDuration = aunchself
					BetterDavey:Clean(LaunchSelfPrompt.Triggered:Connect(function()
						onLaunchTriggered(child)
					end))
				end

				BetterDavey:Clean(blocks.ChildAdded:Connect(setupCannon))

				for _, child in blocks:GetChildren() do
					setupCannon(child)
				end
			else
				setCannonSpeeds(blocks, defaultaim, defaulttnt, defaultself)
			end
		end
    })

	AJ = BetterDavey:CreateToggle({
		Name = "Auto-Jump",
		Default = true																																																						,
				Visible = true
	})	
	AS = BetterDavey:CreateToggle({
		Name = "Auto-Switch",
		Default = false																																																						,
				Visible = true
	})																																																				
	A = BetterDavey:CreateSlider({
		Name = "Aim",
		Visible = false,
		Min = 0,
		Max = 1,
		Default = aim,
		Decimal = 10,
		Function = function(v)
			aim = v
            local worldFolder = getWorldFolder()
            if not worldFolder then return end
            local blocks = worldFolder:WaitForChild("Blocks")
            setCannonSpeeds(blocks, aim, tnt, aunchself)
		end
	})

	T = BetterDavey:CreateSlider({
		Name = "Tnt",
		Visible = false,
		Min = 0,
		Max = 1,
		Default = tnt,
		Decimal = 10,
		Function = function(v)
			tnt = v
            local worldFolder = getWorldFolder()
            if not worldFolder then return end
            local blocks = worldFolder:WaitForChild("Blocks")
            setCannonSpeeds(blocks, aim, tnt, aunchself)
		end
	})

	L = BetterDavey:CreateSlider({
		Name = "Launch Self",
		Visible = false,
		Min = 0,
		Max = 1,
		Default = aunchself,
		Decimal = 10,
		Function = function(v)
			aunchself = v
            local worldFolder = getWorldFolder()
            if not worldFolder then return end
            local blocks = worldFolder:WaitForChild("Blocks")
            setCannonSpeeds(blocks, aim, tnt, aunchself)
		end
	})

	C = BetterDavey:CreateToggle({
		Name = "Customize",
		Default = false,
				Visible = true,
		Function = function(v)
			A.Object.Visible = v
			T.Object.Visible = v
			L.Object.Visible = v
			if not v then
				aim = 0.158
				tnt = 0.0045
				aunchself = 0.395
			end
		end
	})

end)

run(function()
	local AntiMagma

	AntiMagma = vape.Categories.World:CreateModule({
		Name = "AntiMagma",
		Tooltip = 'allows you not to be instantly killed by magma',
		Function = function(callback)
			if callback then
				local function disableMagmaPart(v)
					if not v:IsA("BasePart") then return end
					if not string.find(string.lower(v.Name), 'magma') then return end
					for _, stuff in v:GetDescendants() do
						if stuff:IsA("TouchTransmitter") then
							pcall(function() stuff:Destroy() end)
						end
					end
				end

				for _, v in workspace:GetDescendants() do
					disableMagmaPart(v)
				end

				AntiMagma:Clean(workspace.DescendantAdded:Connect(function(v)
					disableMagmaPart(v)
				end))
				local worldFolder = getWorldFolder()
				if not worldFolder then return end
				local blocks = worldFolder:WaitForChild("Blocks", 1)
				if not blocks then return end
				AntiMagma:Clean(blocks.ChildAdded:Connect(function(v)
					disableMagmaPart(v)
				end))
			end
		end
	})
end)

run(function()
	local TrapESP
	local Background = {}
	local Color = {}
	local Reference = {}
	local Folder = Instance.new('Folder')
	Folder.Parent = vape.gui

	local function Added(v, icon)
		local billboard = Instance.new('BillboardGui')
		billboard.Parent = Folder
		billboard.Name = icon
		billboard.StudsOffsetWorldSpace = Vector3.new(0, 3, 0)
		billboard.Size = UDim2.fromOffset(36, 36)
		billboard.AlwaysOnTop = true
		billboard.ClipsDescendants = false
		billboard.Adornee = v
		local blur = addBlur(billboard)
		blur.Visible = Background.Enabled
		local image = Instance.new('ImageLabel')
		image.Size = UDim2.fromOffset(36, 36)
		image.Position = UDim2.fromScale(0.5, 0.5)
		image.AnchorPoint = Vector2.new(0.5, 0.5)
		image.BackgroundColor3 = Color3.fromHSV(Color.Hue, Color.Sat, Color.Value)
		image.BackgroundTransparency = 1 - (Background.Enabled and Color.Opacity or 0)
		image.BorderSizePixel = 0
		local result = bedwars.getIcon({itemType = icon}, true)
		image.Image = result		
		image.Image = result
		image.Parent = billboard
		local uicorner = Instance.new('UICorner')
		uicorner.CornerRadius = UDim.new(0, 4)
		uicorner.Parent = image
		Reference[v] = billboard
	end
	


	TrapESP = vape.Categories.Render:CreateModule({
		Name = 'TrapESP',
		Function = function(callback)
			if callback then
				TrapESP:Clean(collectionService:GetInstanceAddedSignal('snap_trap'):Connect(function(v)
					if tostring(v:GetAttribute("SnapTrapTeamId")) == lplr.Team.Name then
						return
					end
					Added(v, 'snap_trap')
				end))
				TrapESP:Clean(collectionService:GetInstanceRemovedSignal('snap_trap'):Connect(function(v)
					if tostring(v:GetAttribute("SnapTrapTeamId")) == lplr.Team.Name then
						return
					end
					if Reference[v] then
						Reference[v]:Destroy()
						Reference[v] = nil
					end
				end))
				for _, v in collectionService:GetTagged('snap_trap') do
					if tostring(v:GetAttribute("SnapTrapTeamId")) == lplr.Team.Name then
						return
					end
					Added(v, 'snap_trap')
				end
			else
				Folder:ClearAllChildren()
				table.clear(Reference)
			end
		end,
		Tooltip = 'allows you to see invisible traps'
	})
	Background = TrapESP:CreateToggle({
		Name = 'Background',
		Function = function(callback)
			if Color.Object then Color.Object.Visible = callback end
			for _, v in Reference do
				v.ImageLabel.BackgroundTransparency = 1 - (callback and Color.Opacity or 0)
				v.Blur.Visible = callback
			end
		end,
		Default = true,
				Visible = true
	})
	Color = TrapESP:CreateColorSlider({
		Name = 'Background Color',
		DefaultValue = 0,
		DefaultOpacity = 0.5,
		Function = function(hue, sat, val, opacity)
			for _, v in Reference do
				v.ImageLabel.BackgroundColor3 = Color3.fromHSV(hue, sat, val)
				v.ImageLabel.BackgroundTransparency = 1 - opacity
			end
		end,
		Darker = true
	})
end)

run(function()
	local MouseTP
	local Mode
	local Movement

	local projectileRemote = {InvokeServer = function() end}
	task.spawn(function()
		projectileRemote = bedwars.Client:Get(remotes.FireProjectile).instance
	end)


	local function getNearestPlayer(selfpos)
		if not selfpos or not entitylib.isAlive then return nil end
		local nearestPlayer, nearestDistance = nil, math.huge

		for _, plr in ipairs(playersService:GetPlayers()) do
			if plr ~= lplr and plr.Character and plr.Character:FindFirstChild("HumanoidRootPart") then
				local dist = (plr.Character.HumanoidRootPart.Position - selfpos).Magnitude
				if dist < nearestDistance then
					nearestDistance = dist
					nearestPlayer = plr
				end
			end
		end
		return nearestPlayer
	end

	local function aimCannon(cannon, targetPos)
		if not cannon or not targetPos then return end
		
		local cannonPos = cannon.Position
		local dist = (targetPos - cannonPos).Magnitude
		
		local heightOffset = (dist * 0.095) + (dist * dist * 0.0011)
		local aimPoint = targetPos + Vector3.new(0, heightOffset, 0)
		
		local Delta = CFrame.lookAt(cannonPos, aimPoint)
		local playerDist = (targetPos - lplr.Character.HumanoidRootPart.Position).Magnitude
		
		local lookVector = Delta.LookVector * (1 + playerDist * 0.007) / math.pi
		
		bedwars.Client:Get('AimCannon'):SendToServer({
			cannonBlockPos = bedwars.BlockController:getBlockPosition(cannonPos),
			lookVector = lookVector
		})
	end

	local function getCannonNear(pos)
		local worldFolder = getWorldFolder()
		if not worldFolder then return end
		local blocks = worldFolder:WaitForChild("Blocks", 1)
		if not blocks then return end

		for _, v in blocks:GetChildren() do
			if v.Name == "cannon" and v:IsA("BasePart") then
				if (v.Position - pos).Magnitude <= 12 then
					return v
				end
			end
		end
		return nil
	end


	local function doTeleport()
		local targetPos = nil

		if Mode.Value == 'Players' then
			local plr = getNearestPlayer(lplr.Character.HumanoidRootPart.Position)
			if not plr then
				vape:CreateNotification("MouseTP", "No nearest players near Me.", 6)
				return
			end
			targetPos = plr.Character.HumanoidRootPart.Position

		elseif Mode.Value == 'Mouse' then
			local rayCheck = RaycastParams.new()
			rayCheck.RespectCanCollide = true
			rayCheck.FilterDescendantsInstances = {lplr.Character, gameCamera}

			local mouse = cloneref(lplr:GetMouse())
			local result = workspace:Raycast(mouse.UnitRay.Origin, mouse.UnitRay.Direction * 10000, rayCheck)

			if result then
				targetPos = result.Position + Vector3.new(0, entitylib.character.HipHeight or 2, 0)
			else
				vape:CreateNotification('MouseTP', 'No position found.', 6)
				return
			end

		elseif Mode.Value == 'Camera' then
			targetPos = gameCamera.CFrame.Position + gameCamera.CFrame.LookVector * 200
		else
			vape:CreateNotification('MouseTP', 'Mode is currently nil. Report to aero or soryed', 6, 'warning')
			return
		end

		if Movement.Value == 'Me' then
			local root = entitylib.character.RootPart
			if root then
				local lookVec = root.CFrame.LookVector
				root.CFrame = CFrame.lookAt(targetPos, targetPos + lookVec)
			end

		elseif Movement.Value == 'Kits' and store.equippedKit == 'davey' then
			local cannon = getCannonNear(lplr.Character.HumanoidRootPart.Position)
			if cannon then
				aimCannon(cannon, targetPos)
			end

		elseif Movement.Value == 'Items' then
			local pearl = getItem('telepearl')
			local fireball = getItem('fireball')
			local tool = store.hand.tool

			if pearl and tool and tool.Name == 'telepearl' then
				local meta = bedwars.ProjectileMeta.telepearl
				local dir = CFrame.lookAt(lplr.Character.HumanoidRootPart.Position, targetPos).LookVector * meta.launchVelocity

				projectileRemote:InvokeServer(
					tool, 'telepearl', 'telepearl',
					lplr.Character.HumanoidRootPart.Position,
					lplr.Character.HumanoidRootPart.Position,
					dir,
					httpService:GenerateGUID(true),
					{drawDurationSeconds = 1, shotId = httpService:GenerateGUID(false)},
					workspace:GetServerTimeNow() - 0.045
				)

			elseif fireball and tool and tool.Name == 'fireball' then
				local meta = bedwars.ProjectileMeta.fireball 
				local dir = CFrame.lookAt(lplr.Character.HumanoidRootPart.Position, targetPos).LookVector * meta.launchVelocity

				projectileRemote:InvokeServer(
					tool, 'fireball', 'fireball',
					lplr.Character.HumanoidRootPart.Position,
					lplr.Character.HumanoidRootPart.Position,
					dir,
					httpService:GenerateGUID(true),
					{drawDurationSeconds = 1, shotId = httpService:GenerateGUID(false)},
					workspace:GetServerTimeNow() - 0.045
				)
			end
		else
			vape:CreateNotification('MouseTP', 'Movement is currently nil. Report to aero or soryed', 6, 'warning')
			return
		end
	end

	MouseTP = vape.Categories.Blatant:CreateModule({
		Name = "MouseTP",
		Tooltip = 'allows you to teleport with various methods',
		Function = function(callback)
			if callback then
				doTeleport()
			end
		end
	})

	Mode = MouseTP:CreateDropdown({
		Name = 'Mode',
		List = {'Players', 'Mouse', 'Camera'},
		Default = 'Players'
	})

	Movement = MouseTP:CreateDropdown({
		Name = "Movement",
		List = {'Me', 'Kits', 'Items'},
		Default = 'Me',
		Tooltip = 'Me-Uses you to teleport\nKits-Uses kits abilities to tp\nitems-Uses items to telport'
	})
end)

run(function()
	local PlayerAttach
	local Range
	local Targets
	local Sorts
	PlayerAttach = vape.Categories.Blatant:CreateModule({
		Name = "PlayerAttach",
		Tooltip = 'teleports you the closest player/npc near you in a specific range',
		Function = function(callback)
			if callback then
				repeat 
					local plrs = entitylib.AllPosition({
						Range = Range.Value,
						Wallcheck = Targets.Walls.Enabled,
						Part = "RootPart",
