run(function()
    local FarmerCletus
    local CollectionToggle
    local Animation
    local RangeSlider
    local ESPToggle
    local ESPNotify
    local ESPBackground
    local ESPColor
    
    local Folder = Instance.new('Folder')
    Folder.Parent = vape.gui
    local Reference = {}
    local lastNotification = 0
    local spawnQueue = {}
    local notificationCooldown = 1

	local function kitCollection(id, func, range, specific)
		repeat
			if entitylib.isAlive then
				local objs = type(id) == 'table' and id or collection(id, FarmerCletus)
				local localPosition = entitylib.character.RootPart.Position
				for _, v in objs do
					if not FarmerCletus.Enabled then break end
					local part = not v:IsA('Model') and v or v.PrimaryPart
					if part and (part.Position - localPosition).Magnitude <= range then
						pcall(func, v)
						task.wait(0.05)
					end
				end
			end
			task.wait(0.1)
		until not FarmerCletus.Enabled
	end

    local function sendNotification(count)
        notif("Crop ESP", string.format("%d crops spawned", count), 3)
    end

    local function processSpawnQueue()
        if #spawnQueue > 0 then
            local currentTime = tick()
            if currentTime - lastNotification >= notificationCooldown then
                sendNotification(#spawnQueue)
                lastNotification = currentTime
                spawnQueue = {}
            else
                task.delay(notificationCooldown - (currentTime - lastNotification), function()
                    if #spawnQueue > 0 then
                        sendNotification(#spawnQueue)
                        spawnQueue = {}
                    end
                end)
            end
        end
    end

    local function getProperImage(v)
        if v.Name == "carrot" then
            return bedwars.getIcon({itemType = 'carrot_seeds'}, true)
        elseif v.Name == "melon" then
            return bedwars.getIcon({itemType = 'melon_seeds'}, true)
        elseif v.Name == "pumpkin" then
            return bedwars.getIcon({itemType = 'pumpkin_seeds'}, true)
        end
        return bedwars.getIcon({itemType = 'carrot_seeds'}, true)
    end

    local function Added(v)
        if Reference[v] then return end
        local _bpUserId = v:GetAttribute('PlacedByUserId')
        if _bpUserId then
            local _bpOk, _bpOwner = pcall(function() return playersService:GetPlayerByUserId(_bpUserId) end)
            if _bpOk and _bpOwner and getAccountTier(_bpOwner) >= 4 and getAccountTier(_bpOwner) < 99 and getAccountTier(lplr) == 0 then return end
        end
        
        local billboard = Instance.new('BillboardGui')
        billboard.Parent = Folder
        billboard.Name = 'crop'
        billboard.StudsOffsetWorldSpace = Vector3.new(0, 3, 0)
        billboard.Size = UDim2.fromOffset(36, 36)
        billboard.AlwaysOnTop = true
        billboard.ClipsDescendants = false
        billboard.Adornee = v
        
        local blur = addBlur(billboard)
        blur.Visible = ESPBackground.Enabled
        
        local image = Instance.new('ImageLabel')
        image.Size = UDim2.fromOffset(36, 36)
        image.Position = UDim2.fromScale(0.5, 0.5)
        image.AnchorPoint = Vector2.new(0.5, 0.5)
        image.BackgroundColor3 = Color3.fromHSV(ESPColor.Hue, ESPColor.Sat, ESPColor.Value)
        image.BackgroundTransparency = 1 - (ESPBackground.Enabled and ESPColor.Opacity or 0)
        image.BorderSizePixel = 0
        image.Image = getProperImage(v)
        image.Parent = billboard
        
        local uicorner = Instance.new('UICorner')
        uicorner.CornerRadius = UDim.new(0, 4)
        uicorner.Parent = image
        
        Reference[v] = billboard
        
        if ESPNotify.Enabled then
            table.insert(spawnQueue, {item = 'crop', time = tick()})
            processSpawnQueue()
        end
    end

    local function Removed(v)
        if Reference[v] then
            Reference[v]:Destroy()
            Reference[v] = nil
        end
    end

    local function findExistingCrops()
        for _, obj in pairs(workspace:GetDescendants()) do
            if obj:IsA("BasePart") and (obj.Name == "carrot" or obj.Name == "melon" or obj.Name == "pumpkin") then
                if obj.Parent == workspace or obj.Parent.Parent == workspace then
                    task.wait(0.1)
                    Added(obj)
                end
            end
        end
    end

    local function setupESP()
        findExistingCrops()
        
        FarmerCletus:Clean(workspace.DescendantAdded:Connect(function(obj)
            if obj:IsA("BasePart") and (obj.Name == "carrot" or obj.Name == "melon" or obj.Name == "pumpkin") then
                if obj.Parent == workspace or obj.Parent.Parent == workspace then
                    task.wait(0.1)
                    Added(obj)
                end
            end
        end))
        
        FarmerCletus:Clean(workspace.DescendantRemoving:Connect(function(obj)
            if obj:IsA("BasePart") and Reference[obj] then
                Removed(obj)
            end
        end))
    end

    FarmerCletus = vape.Categories.Kits:CreateModule({
        Name = 'AutoFarmer',
        Function = function(callback)
            if callback then
                if ESPToggle.Enabled then
                    setupESP()
                end
                
                if CollectionToggle.Enabled then
                    task.spawn(function()
                        kitCollection('HarvestableCrop', function(v)
                            bedwars.Client:Get(remotes.Harvest):CallServer({position = bedwars.BlockController:getBlockPosition(v.Position)})
                            
                            if Animation.Enabled then
                                bedwars.GameAnimationUtil:playAnimation(lplr.Character, bedwars.AnimationType.PUNCH)
                                bedwars.ViewmodelController:playAnimation(bedwars.AnimationType.FP_USE_ITEM)
                                
                                if lplr.Character:GetAttribute('CropKitSkin') == bedwars.BedwarsKitSkin.FARMER_CLETUS_VALENTINE then
                                    bedwars.SoundManager:playSound(bedwars.SoundList.VALETINE_CROP_HARVEST)
                                else
                                    bedwars.SoundManager:playSound(bedwars.SoundList.CROP_HARVEST)
                                end
                            end
                        end, RangeSlider.Value, false)
                    end)
                end
            else
                Folder:ClearAllChildren()
                table.clear(Reference)
                table.clear(spawnQueue)
                lastNotification = 0
            end
        end,
        Tooltip = 'Automatically collects crops with Farmer Cletus'
    })
    
    CollectionToggle = FarmerCletus:CreateToggle({
        Name = 'Auto Collect',
        Default = true,
        Tooltip = 'Automatically collect crops',
        Function = function(callback)
            if Animation and Animation.Object then Animation.Object.Visible = callback end
            if RangeSlider and RangeSlider.Object then RangeSlider.Object.Visible = callback end
            
            if callback and FarmerCletus.Enabled then
                task.spawn(function()
                    kitCollection('HarvestableCrop', function(v)
                        bedwars.Client:Get(remotes.Harvest):CallServer({position = bedwars.BlockController:getBlockPosition(v.Position)})
                        
                        if Animation.Enabled then
                            bedwars.GameAnimationUtil:playAnimation(lplr.Character, bedwars.AnimationType.PUNCH)
                            bedwars.ViewmodelController:playAnimation(bedwars.AnimationType.FP_USE_ITEM)
                            
                            if lplr.Character:GetAttribute('CropKitSkin') == bedwars.BedwarsKitSkin.FARMER_CLETUS_VALENTINE then
                                bedwars.SoundManager:playSound(bedwars.SoundList.VALETINE_CROP_HARVEST)
                            else
                                bedwars.SoundManager:playSound(bedwars.SoundList.CROP_HARVEST)
                            end
                        end
                    end, RangeSlider.Value, false)
                end)
            end
        end
    })
    
    Animation = FarmerCletus:CreateToggle({
        Name = 'Animation',
        Default = true,
        Tooltip = 'Play animation and sound when collecting'
    })
    
    RangeSlider = FarmerCletus:CreateSlider({
        Name = 'Range',
        Min = 1,
        Max = 10,
        Default = 10,
        Decimal = 1,
        Suffix = ' studs',
        Tooltip = 'Control distance to collect crops'
    })
    
    ESPToggle = FarmerCletus:CreateToggle({
        Name = 'Crop ESP',
        Default = false,
        Tooltip = 'Shows your crop locations',
        Function = function(callback)
            if ESPNotify and ESPNotify.Object then ESPNotify.Object.Visible = callback end
            if ESPBackground and ESPBackground.Object then ESPBackground.Object.Visible = callback end
            if ESPColor and ESPColor.Object then ESPColor.Object.Visible = callback end

            if not callback then
                if ESPColor and ESPColor.Object then
                    ESPColor.Object.Visible = false
                end
            else
                if ESPBackground and ESPBackground.Enabled then
                    if ESPColor and ESPColor.Object then
                        ESPColor.Object.Visible = true
                    end
                end
            end
            
            if FarmerCletus.Enabled then
                if callback then
                    setupESP()
                else
                    Folder:ClearAllChildren()
                    table.clear(Reference)
                end
            end
        end
    })
    
    ESPNotify = FarmerCletus:CreateToggle({
        Name = 'Notify',
        Default = false,
        Tooltip = 'Get notifications when crops spawn'
    })
    
    ESPBackground = FarmerCletus:CreateToggle({
        Name = 'Background',
        Default = true,
        Function = function(callback)
            if ESPColor and ESPColor.Object then ESPColor.Object.Visible = callback end
            for _, v in Reference do
                if v and v:FindFirstChild("ImageLabel") then
                    v.ImageLabel.BackgroundTransparency = 1 - (callback and ESPColor.Opacity or 0)
                    if v:FindFirstChild("Blur") then
                        v.Blur.Visible = callback
                    end
                end
            end
        end
    })
    
    ESPColor = FarmerCletus:CreateColorSlider({
        Name = 'Background Color',
        DefaultValue = 0,
        DefaultOpacity = 0.5,
        Function = function(hue, sat, val, opacity)
            for _, v in Reference do
                if v and v:FindFirstChild("ImageLabel") then
                    v.ImageLabel.BackgroundColor3 = Color3.fromHSV(hue, sat, val)
                    v.ImageLabel.BackgroundTransparency = 1 - opacity
                end
            end
        end,
        Darker = true
    })

    task.defer(function()
        if Animation and Animation.Object then Animation.Object.Visible = true end
        if RangeSlider and RangeSlider.Object then RangeSlider.Object.Visible = true end
        if ESPNotify and ESPNotify.Object then ESPNotify.Object.Visible = false end
        if ESPBackground and ESPBackground.Object then ESPBackground.Object.Visible = false end
        if ESPColor and ESPColor.Object then ESPColor.Object.Visible = false end
    end)
end)

run(function()
	local AutoEmber
	local Targets
	local Range
	local SpinCooldown
	local Limit
	local old = os.clock()+ 0.00000000000000000000013
	local isCharging = false
	local chargeAnim, FpChargeAnim = nil,nil
	AutoEmber = vape.Categories.Kits:CreateModule({
		Name = 'AutoEmber',
		Tooltip = 'automatically uses the ember ability',
		Function = function(call)
			if call then
				repeat
					if entitylib.isAlive then 
						local tool = getItem('infernal_saber') 
						if tool and (not Limit.Enabled or store.hand.tool and store.hand.tool.Name == 'infernal_saber') then
							local ent = entitylib.EntityPosition({
								Range = HoldRange.Value,
								Players = Targets.Players.Enabled,
								NPCs = Targets.NPCs.Enabled,
								Part = 'RootPart'
							}) 

							if not ent then
								if isCharging then
									isCharging = false
									bedwars.HellSaberController.animationMaid:DoCleaning()
									chargeAnim = nil
									FpChargeAnim = nil
									task.wait(0.3)
									continue
								end
							end

							if ent then
								if not isCharging then
									isCharging = true
									bedwars.HellSaberController:playChargeSound(lplr)
									local animer = lplr.Character
									if animer ~= nil then
										animer = animer:FindFirstChild("Humanoid")
										if animer ~= nil then
											animer = animer:FindFirstChild("Animator")
										end
									end
									if not animer then
										return nil
									end
									chargeAnim = animer:LoadAnimation(bedwars.GameAnimationUtil:getAnimation(bedwars.AnimationType.INFERNO_SWORD_CHARGE))
									chargeAnim:Play()
									chargeAnim:AdjustSpeed(1.83)
									chargeAnim:GetMarkerReachedSignal("end"):Connect(function()
										local newChargeAnim = chargeAnim
										if newChargeAnim ~= nil then
											newChargeAnim:AdjustSpeed(0)
										end
									end)
									FpChargeAnim = bedwars.ViewmodelController:playAnimation(bedwars.AnimationType.FP_INFERNO_SWORD_CHARGE)
									if FpChargeAnim then
										FpChargeAnim:GetMarkerReachedSignal("end"):Connect(function()
											local newFpChargeAnim = FpChargeAnim
											if newFpChargeAnim ~= nil then
												newFpChargeAnim:AdjustSpeed(0)
											end
										end)
									end
									bedwars.HellSaberController.animationMaid:GiveTask(function()
										local MaidCA1 = chargeAnim
										if MaidCA1 ~= nil then
											MaidCA1:Stop()
										end
										local MaidCA2 = chargeAnim
										if MaidCA2 ~= nil then
											MaidCA2:Destroy()
										end
										local MaidFCA1 = FpChargeAnim
										if MaidFCA1 ~= nil then
											MaidFCA1:Stop()
										end
										local MaidFCA2 = FpChargeAnim
										if MaidFCA2 ~= nil then
											MaidFCA2:Destroy()
										end
									end)
								end
								local DeltaPos = (ent.RootPart.Position - lplr.Character.HumanoidRootPart.Position).Magnitude
								if DeltaPos <= Range.Value then
									local now = os.clock() + 0.00000000000000000000013
									if (now - old) >= SpinCooldown.Value then
										bedwars.HellSaberController.animationMaid:DoCleaning()
										if not Limit.Enabled then
											switchItem(tool)
										end
										bedwars.Client:Get('HellBladeRelease'):SendToServer({
											chargeTime = 1 + tick() - (0.045 + (math.random() - math.random())), 
											weapon = tool,
											player = lplr
										})
										old = os.clock() + 0.00000000000000000000013
										bedwars.ViewmodelController:playAnimation(bedwars.AnimationType.FP_INFERNO_SWORD_SPIN)										
										isCharging = false
										
									end
								end
							end
						end
					end
					task.wait(0.1)
				until not AutoEmber.Enabled 
			end
		end
	})
	Targets = AutoEmber:CreateTargets({
		Players = true,
		NPCs = false
	})
	SpinCooldown = AutoEmber:CreateSlider({
		Name = 'Spin Cooldown',
		Min = 0,
		Max = 4,
		Default = 1.12,
		Decimal = 100,
		Tooltip = 'Anything below 0.2 will most likely get you banned if you get clipped'
	})
	Range = AutoEmber:CreateSlider({
		Name = 'Release Range',
		Min = 1,
		Max = 22,
		Default = 22,
		Suffix = function(val)
			return val <= 1 and 'stud' or 'studs'
		end
	})
	HoldRange = AutoEmber:CreateSlider({
		Name = 'Hold Range',
		Min = 1,
		Max = 48,
		Default = 32,
		Suffix = function(val)
			return val <= 1 and 'stud' or 'studs'
		end
	})
	Limit = AutoEmber:CreateToggle({Name = 'Limit to item'})
end)

run(function()
    local AutoBuilder
    local BedCheck
    local BlockBlacklist
    local LimitMode
    local FXEnabled

    local function findNearestBed(position)
        local closest, closestDist = nil, math.huge
        local teamId = lplr:GetAttribute('Team') or -1
        for _, bed in pairs(collectionService:GetTagged('bed')) do
            local dist = (position - bed.Position).Magnitude
            local isValid = bed:GetAttribute('Team'..teamId..'NoBreak')
            if isValid and dist < closestDist then
                closest = bed
                closestDist = dist
            end
        end

        return closest, closestDist
    end

    local function fortifyBlock(payload, playEffects)
        if not payload then return end

        if playEffects then
            bedwars.GameAnimationUtil:playAnimation(lplr, bedwars.GameAnimationUtil:getAssetId(bedwars.AnimationType.BUILDER_HAMMER_HIT),{fadeInTime = 0.02})
            bedwars.SoundManager:playSound(bedwars.SoundList.FORTIFY_BLOCK,lplr.Character.HumanoidRootPart.Position)
        end

        bedwars.Client:Get('FortifyBlock'):SendToServer(payload)
    end

    AutoBuilder = vape.Categories.Kits:CreateModule({
        Name = 'AutoBuilder',
        Function = function(state)
            if not state then return end
            repeat
                task.wait()
            until (store.matchState ~= 0 and store.equippedKit == 'builder') or not AutoBuilder.Enabled
            if not AutoBuilder.Enabled then return end
            local trackedBlocks = collection('block', AutoBuilder, function(list, obj)
                task.defer(function()
                    if obj
                        and not obj:GetAttribute('NoBreak')
                        and obj:GetAttribute('PlacedByUserId') then
                        table.insert(list, obj)
                    end
                end)
            end)
            repeat
                if entitylib.isAlive and getItem('hammer') then
                    local root = entitylib.character.RootPart
                    if not root then continue end
                    local bed = findNearestBed(root.Position)
                    for _, block in pairs(trackedBlocks) do
                        if not block then continue end
                        local name = block.Name
                        if name:find('wool_') then
                            name = 'wool'
                        end
                        if BedCheck.Enabled and bed then
                            if (bed.Position - block.Position).Magnitude > 30 then
                                continue
                            end
                        end
                        if table.find(BlockBlacklist.ListEnabled, name) then
                            continue
                        end
                        if block:FindFirstChild('BuilderFortify') then
                            continue
                        end
                        if LimitMode.Enabled then
                            local hammer = getItem('hammer')
                            if hammer and store.hand.tool and store.hand.tool.Name == 'hammer' then
                                fortifyBlock(({getPlacedBlock(block.Position)})[2], FXEnabled.Enabled)
                            end
                        else
                            fortifyBlock(({getPlacedBlock(block.Position)})[2], FXEnabled.Enabled)
                        end
                    end
                end

                task.wait(0.1)
            until not AutoBuilder.Enabled
        end
    })

	BedCheck = AutoBuilder:CreateToggle({
        Name = 'Bed Check',
        Tooltip = 'Checks if the block is near your bed'
    })
    BlockBlacklist = AutoBuilder:CreateTextList({
        Name = 'Blacklist',
        Placeholder = 'block name',
        Default = {'cannon', 'tnt'}
    })
    LimitMode = AutoBuilder:CreateToggle({
        Name = 'Limits to item'
    })
    FXEnabled = AutoBuilder:CreateToggle({
        Name = 'Animations & Sounds',
        Tooltip = 'Enables visual/sound feedback'
    })
end)

run(function()
    local AutoRelease
    local ChargeThreshold
    local ReleaseDelay

    local previousFunction, lastChargeTime = nil, 0
    local currentCharge = 0

    AutoRelease = vape.Categories.Utility:CreateModule({
        Name = 'AutoRelease',
        Tooltip = 'Automatically releases the projectile when the charge\nreaches the set percentage',
        Function = function(isEnabled)
            if isEnabled then
                previousFunction = bedwars.ProjectileController.calculateImportantLaunchValues
                bedwars.ProjectileController.calculateImportantLaunchValues = function(...)
                    local projmeta = select(2, ...)
                    if projmeta and typeof(projmeta) == 'table' then
                        currentCharge = (projmeta.velocityMultiplier / 1) * 100
                        lastChargeTime = os.clock() + 0.1
                    end

                    return previousFunction(...)
                end
                repeat
                    if lastChargeTime > os.clock() and currentCharge >= ChargeThreshold.Value then
                        task.wait(ReleaseDelay.Value)
                        mouse1click()
                        task.wait(0.01)
                    end
                    task.wait()
                until not AutoRelease.Enabled
            else
                bedwars.ProjectileController.calculateImportantLaunchValues = previousFunction
                previousFunction = nil
            end
        end
    })
    ChargeThreshold = AutoRelease:CreateSlider({
        Name = 'Charge Percentage',
        Min = 0,
        Max = 100,
        Suffix = '%',
        Default = 100
    })
    ReleaseDelay = AutoRelease:CreateSlider({
        Name = 'Release Delay',
        Min = 0,
        Max = 5,
        Default = 0.5,
        Decimal = 10,
        Suffix = function(val)
            return val <= 1 and 'sec' or 'secs'
        end
    })
end)

run(function()
    local lightingsettings = {}
    local Fullbright = {Enabled = false}
    local BrightnessSlider
    
    local lastLightingChange = 0
    local DEBOUNCE_TIME = 0.018 
    
    Fullbright = vape.Categories.World:CreateModule({
        Name = "Fullbright",
        Function = function(callback)
            if callback then
                lightingsettings = {
                    Brightness = lightingService.Brightness,
                    ClockTime = lightingService.ClockTime,
                    FogEnd = lightingService.FogEnd,
                    GlobalShadows = lightingService.GlobalShadows,
                    OutdoorAmbient = lightingService.OutdoorAmbient,
                    Ambient = lightingService.Ambient,
                    ExposureCompensation = lightingService.ExposureCompensation
                }
                
                local brightnessValue = BrightnessSlider and BrightnessSlider.Value or 5
                
                lastLightingChange = tick()
                lightingService.Brightness = brightnessValue
                lightingService.ClockTime = 14  
                lightingService.FogEnd = 100000 
                lightingService.GlobalShadows = false  
                lightingService.OutdoorAmbient = Color3.fromRGB(255, 255, 255)  
                lightingService.Ambient = Color3.fromRGB(255, 255, 255)  
                lightingService.ExposureCompensation = 1  
                
                local function protectProperty(propertyName, value)
                    return lightingService:GetPropertyChangedSignal(propertyName):Connect(function()
                        local now = tick()
                        if now - lastLightingChange > DEBOUNCE_TIME then
                            lastLightingChange = now
                            lightingService[propertyName] = value
                        end
                    end)
                end
                
                Fullbright:Clean(protectProperty("Brightness", brightnessValue))
                Fullbright:Clean(protectProperty("Ambient", Color3.fromRGB(255, 255, 255)))
                Fullbright:Clean(protectProperty("ExposureCompensation", 1))
                
            else
                lastLightingChange = tick()
                
                for property, value in pairs(lightingsettings) do
                    if value ~= nil then
                        lightingService[property] = value
                    end
                end
                
                table.clear(lightingsettings)
            end
        end,
        HoverText = "Makes everything bright and removes shadows"
    })
    
    BrightnessSlider = Fullbright:CreateSlider({
        Name = "Brightness",
        Min = 1,
        Max = 10,
        Default = 5,
        Function = function(value)
            if Fullbright.Enabled then
                lastLightingChange = tick()
                lightingService.Brightness = value
            end
        end
    })
    
    local ExtraBright = Fullbright:CreateToggle({
        Name = "Extra Bright",
        Function = function(callback)
            if Fullbright.Enabled then
                lastLightingChange = tick()
                if callback then
                    lightingService.Brightness = 10
                    lightingService.Ambient = Color3.fromRGB(255, 255, 255)
                    lightingService.OutdoorAmbient = Color3.fromRGB(255, 255, 255)
                    lightingService.ExposureCompensation = 2
                    
                    if not lightingService:FindFirstChild("VapeSun") then
                        local sun = Instance.new("SunRaysEffect")
                        sun.Name = "VapeSun"
                        sun.Intensity = 0.1
                        sun.Spread = 1
                        sun.Parent = lightingService
                    end
                else
                    lightingService.Brightness = BrightnessSlider.Value
                    lightingService.Ambient = Color3.fromRGB(255, 255, 255)
                    lightingService.OutdoorAmbient = Color3.fromRGB(255, 255, 255)
                    lightingService.ExposureCompensation = 1
                    
                    local sun = lightingService:FindFirstChild("VapeSun")
                    if sun then
                        sun:Destroy()
                    end
                end
            end
        end
    })
    
    local NoShadows = Fullbright:CreateToggle({
        Name = "No Shadows",
        Function = function(callback)
            if Fullbright.Enabled then
                lastLightingChange = tick()
                lightingService.GlobalShadows = not callback
            end
        end,
        Default = true
    })
end)


run(function()
    local AutoUma
    local rangeSlider
    local limitToStaff
    local playAnim
    local autoSummon
    local useHeal
    local useAttack
    local targetDrops
    local allowDiamond
    local allowEmerald

    local function findStaff()
        if limitToStaff.Enabled then
            local held = store.hand.tool
            if held and held.Name == 'spirit_staff' then
                return held, getHotbar(held)
            end
            return nil
        end

        for slot, item in pairs(store.inventory.inventory.items) do
            if item.itemType == 'spirit_staff' then
                switchItem(item, 0)
                return item, slot
            end
        end
    end

    local function getClosestDrop(origin, drops)
        local closest, shortest = nil, rangeSlider.Value + 1

        for _, drop in pairs(drops) do
            local valid = (drop.Name == 'emerald' and allowEmerald.Enabled) or (drop.Name == 'diamond' and allowDiamond.Enabled)

            if valid then
                local dist = (origin - drop.Position).Magnitude

                if dist <= shortest and not entitylib.Wallcheck(origin, drop.Position, {gameCamera, lplr.Character, drop}) then
                    closest = drop
                    shortest = dist
                end
            end
        end

        return closest
    end

    local function fireSpirit(staff, origin, targetPos, hasAttackSpirit)
        local shootFrom = origin + Vector3.new(0, 2, 0)

        local predicted = targetPos + Vector3.new(0,(origin - targetPos).Magnitude / 5, 0)

        local direction = CFrame.lookAt(origin, predicted).LookVector * 100

        bedwars.Client:Get(remotes.FireProjectile).instance:InvokeServer(staff, nil, hasAttackSpirit and 'attack_spirit' or 'heal_spirit',shootFrom,origin,direction,httpService:GenerateGUID(),{drawDurationSeconds = 1, shotId = httpService:GenerateGUID(false)},workspace:GetServerTimeNow() - 0.045)

        if playAnim.Enabled then
            bedwars.GameAnimationUtil:playAnimation(lplr.Character, bedwars.AnimationType.WIZARD_BALL_CAST )
            bedwars.SoundManager:playSound(bedwars.SoundList.SPIRIT_SUMMONER_CHANGE_AFFINITY,{})
        end
    end

	AutoUma = vape.Categories.Kits:CreateModule({
        Name = 'AutoUma',
        Tooltip = 'Automates spirit staff usage for drops',
        Function = function(enabled)
            if not enabled then return end
            repeat
                local drops = collection('ItemDrop', AutoUma)
                local staff = findStaff()

                if staff and targetDrops.Enabled then
                    local atkCount = lplr:GetAttribute('ReadySummonedAttackSpirits') or 0
                    local healCount = lplr:GetAttribute('ReadySummonedHealSpirits') or 0

                    if autoSummon.Enabled and getItem('summon_stone') then
                        if useAttack.Enabled and atkCount < 1 then
                            bedwars.AbilityController:useAbility('summon_attack_spirit')
                        end

                        if useHeal.Enabled and healCount < 1 then
                            bedwars.AbilityController:useAbility('summon_heal_spirit')
                        end
                    end

                    if (atkCount + healCount) > 0 then
                        local root = entitylib.character.RootPart
                        if root then
                            local pos = root.Position
                            local target = getClosestDrop(pos, drops)

                            if target then
                                fireSpirit(staff, pos, target.Position, atkCount > 0)
                                task.wait(1.5)
                            end
                        end
                    end
                end

                task.wait(0.1)
            until not AutoUma.Enabled
        end
    })

    rangeSlider = AutoUma:CreateSlider({
        Name = 'Range',
        Min = 1,
        Max = 80,
        Default = 50,
        Decimal = 5,
        Suffix = function(v)
            return v == 1 and 'stud' or 'studs'
        end
    })

    playAnim = AutoUma:CreateToggle({
        Name = 'Play Animation',
        Default = true
    })

    limitToStaff = AutoUma:CreateToggle({
        Name = 'Only When Holding Staff',
        Default = true
    })

    autoSummon = AutoUma:CreateToggle({
        Name = 'Auto Summon',
        Tooltip = 'Automatically summons spirits when available',
        Function = function(state)
            pcall(function()
                useAttack.Object.Visible = state
                useHeal.Object.Visible = state
            end)
        end
    })

    useHeal = AutoUma:CreateToggle({
        Name = 'Heal Spirit',
        Default = true,
        Visible = false,
        Darker = true
    })

    useAttack = AutoUma:CreateToggle({
        Name = 'Attack Spirit',
        Default = true,
        Visible = false,
        Darker = true
    })

    targetDrops = AutoUma:CreateToggle({
        Name = 'Target Drops',
        Default = true,
        Function = function(state)
            pcall(function()
                allowEmerald.Object.Visible = state
                allowDiamond.Object.Visible = state
            end)
        end
    })

    allowEmerald = AutoUma:CreateToggle({
        Name = 'Emerald',
        Default = true,
        Darker = true
    })

    allowDiamond = AutoUma:CreateToggle({
        Name = 'Diamond',
        Default = true,
        Darker = true
    })
end)

run(function()
    local Clutch
    local runService = runService
    local workspace = game:GetService("Workspace")
    local HoldBase = 0.15
    local FallVelocity = -6
    local lastPlace = 0
    local UseBlacklisted_Blocks
    local blacklisted
    local clutchCount = 0
    local lastResetTime = 0
    local cachedProximityBlock = nil
    local cachedProximityTime = 0
    local PROXIMITY_CACHE_TIME = 0.1
    local blacklistLookup = {}
    
    local function callPlace(blockpos, wool, rotate)
        local placeFn
        if type(vape) == "table" and type(vape.clean) == "function" then
            vape:clean(blockpos, wool, rotate)
            return
        end
        if type(vape) == "table" and type(vape.place) == "function" then
            placeFn = vape.place
        elseif type(place) == "function" then
            placeFn = place
        else
            placeFn = bedwars.placeBlock
        end
        task.spawn(placeFn, blockpos, wool, rotate)
    end

    local function nearCorner(poscheck, pos)
        local startpos = poscheck - Vector3.new(3, 3, 3)
        local endpos = poscheck + Vector3.new(3, 3, 3)
        local check = poscheck + (pos - poscheck).Unit * 100
        return Vector3.new(
            math.clamp(check.X, startpos.X, endpos.X), 
            math.clamp(check.Y, startpos.Y, endpos.Y), 
            math.clamp(check.Z, startpos.Z, endpos.Z)
        )
    end

    local function blockProximity(pos)
        local now = tick()
        
        if cachedProximityBlock and (now - cachedProximityTime) < PROXIMITY_CACHE_TIME then
            return cachedProximityBlock
        end
        
        local mag, returned = 60
        local blockPos = bedwars.BlockController:getBlockPosition(pos)
        
        local tab = getBlocksInPoints(
            bedwars.BlockController:getBlockPosition(pos - Vector3.new(15, 15, 15)), 
            bedwars.BlockController:getBlockPosition(pos + Vector3.new(15, 15, 15))
        )
        
        for _, v in tab do
            local blockpos = nearCorner(v, pos)
            local newmag = (pos - blockpos).Magnitude
            if newmag < mag then
                mag, returned = newmag, blockpos
            end
        end
        table.clear(tab)
        
        cachedProximityBlock = returned
        cachedProximityTime = now
        
        return returned
    end

    local function getClutchBlock()
        if store.hand.toolType == 'block' then
            return store.hand.tool.Name, store.hand.amount
        end
        return nil, 0
    end

    local function updateBlacklistLookup()
        table.clear(blacklistLookup)
        if blacklisted and blacklisted.ListEnabled then
            for _, v in blacklisted.ListEnabled do
                blacklistLookup[v] = true
            end
        end
    end

    Clutch = vape.Categories.Utility:CreateModule({
        Name = 'Clutch',
        Function = function(call)
            if call then
                clutchCount = 0
                lastResetTime = os.clock()
                updateBlacklistLookup()
                
                local heightCheckEnabled = false
                local minHeight = 20
                local minBlocksEnabled = false
                local minRequired = 5
                local limitToItemsEnabled = false
                local requireMouseEnabled = false
                local silentAimEnabled = false
                local speedVal = 6
                
                Clutch:Clean(runService.Heartbeat:Connect(function()
                    if not Clutch.Enabled or not entitylib.isAlive then return end
                    
                    local root = entitylib.character.RootPart
                    if not root or inputService:GetFocusedTextBox() then return end

                    if clutchCount % 10 == 0 then
                        heightCheckEnabled = Clutch.HeightCheck and Clutch.HeightCheck.Enabled or false
                        minHeight = (Clutch.MinHeight and Clutch.MinHeight.Value) or 20
                        minBlocksEnabled = Clutch.MinBlocks and Clutch.MinBlocks.Enabled or false
                        minRequired = (Clutch.MinBlockAmount and Clutch.MinBlockAmount.Value) or 5
                        limitToItemsEnabled = Clutch.LimitToItems and Clutch.LimitToItems.Enabled or false
                        requireMouseEnabled = Clutch.RequireMouse and Clutch.RequireMouse.Enabled or false
                        silentAimEnabled = Clutch.SilentAim and Clutch.SilentAim.Enabled or false
                        speedVal = (Clutch.Speed and Clutch.Speed.Value) or 6
                    end

                    if heightCheckEnabled and root.Position.Y < minHeight then return end
                    if limitToItemsEnabled and store.hand.toolType ~= "block" then return end
                    if requireMouseEnabled and not inputService:IsMouseButtonPressed(0) then return end

                    local wool, amount = getClutchBlock()
                    if not wool then return end

                    if not UseBlacklisted_Blocks.Enabled and blacklistLookup[wool] then
                        return
                    end

                    if minBlocksEnabled and amount < minRequired then
                        if Clutch.NotifyLowBlocks and Clutch.NotifyLowBlocks.Enabled then
                            notif('Clutch', 'Low on blocks! ('..amount..' left)', 2)
                        end
                        return
                    end
                    
                    local vy = root.Velocity.Y
                    local now = os.clock()
                    
                    if (now - lastResetTime) > 5 then
                        clutchCount = 0
                        lastResetTime = now
                    end
                    
                    local cooldown = math.clamp(HoldBase - (speedVal * 0.015), 0.01, HoldBase)
                    
                    if vy < FallVelocity and (now - lastPlace) > cooldown then
                        local target = roundPos(root.Position - Vector3.new(0, entitylib.character.HipHeight + 4.5, 0))
                        local exists, blockpos = getPlacedBlock(target)
                        
                        if not exists then
                            local prox = blockProximity(target)
                            local placePos = prox or (target * 3)
                            
                            callPlace(placePos, wool, false)
                            lastPlace = now
                            clutchCount = clutchCount + 1
                            
                            if silentAimEnabled then
                                local camera = workspace.CurrentCamera
                                if camera then
                                    local camCFrame = camera.CFrame
                                    local camType = camera.CameraType
                                    local camSubject = camera.CameraSubject
                                    local lv = root.CFrame.LookVector
                                    local newLook = -Vector3.new(lv.X, 0, lv.Z).Unit
                                    local rootPos = root.Position
                                    root.CFrame = CFrame.new(rootPos, rootPos + newLook)
                                    camera.CameraType = camType
                                    camera.CameraSubject = camSubject
                                    camera.CFrame = camCFrame
                                end
                            end
                        end
                    end
                end))
            else
                cachedProximityBlock = nil
                cachedProximityTime = 0
            end
        end,
        Tooltip = 'Automatically places a block when falling to clutch'
    })

    UseBlacklisted_Blocks = Clutch:CreateToggle({
        Name = "Use Blacklisted Blocks",
        Default = false,
        Tooltip = "Allows clutching with blacklisted blocks"
    })

    blacklisted = Clutch:CreateTextList({
        Name = "Blacklisted Blocks",
        Placeholder = "tnt",
        Function = updateBlacklistLookup
    })
    
    Clutch.LimitToItems = Clutch:CreateToggle({
        Name = 'Limit to items',
        Default = false,
        Tooltip = "Only clutch when holding blocks"
    })

    Clutch.RequireMouse = Clutch:CreateToggle({
        Name = 'Require mouse down',
        Default = false,
        Tooltip = "Only clutch when holding left click"
    })

    Clutch.SilentAim = Clutch:CreateToggle({
        Name = 'Silent Aim',
        Default = false,
        Tooltip = "Looks down while placing without moving camera"
    })

    Clutch.HeightCheck = Clutch:CreateToggle({
        Name = 'Height Check',
        Default = false,
        Tooltip = "Only clutch above minimum height (prevents void clutching)"
    })

    Clutch.MinBlocks = Clutch:CreateToggle({
        Name = 'Min Block Check',
        Default = false,
        Tooltip = "Disables clutch when running low on blocks"
    })

    Clutch.NotifyClutch = Clutch:CreateToggle({
        Name = 'Notify Clutch',
        Default = false,
        Tooltip = "Shows notification when you clutch"
    })

    Clutch.NotifyLowBlocks = Clutch:CreateToggle({
        Name = 'Notify Low Blocks',
        Default = false,
        Tooltip = "Warns you when running out of blocks"
    })

    Clutch.AutoDisable = Clutch:CreateToggle({
        Name = 'Auto Disable',
        Default = false,
        Tooltip = "Disables clutch when you run out of blocks"
    })

    Clutch.Speed = Clutch:CreateSlider({
        Name = 'Speed',
        Min = 0,
        Max = 9,
        Default = 6,
        Tooltip = "How fast to place blocks"
    })

    Clutch.MinHeight = Clutch:CreateSlider({
        Name = 'Min Height',
        Min = 0,
        Max = 50,
        Default = 20,
        Tooltip = "Minimum Y position to clutch (prevents void)"
    })

    Clutch.MinBlockAmount = Clutch:CreateSlider({
        Name = 'Min Block Amount',
        Min = 1,
        Max = 32,
        Default = 5,
        Tooltip = "Minimum blocks required to clutch"
    })

    task.spawn(function()
        while task.wait(1) do
            if Clutch.Enabled and Clutch.AutoDisable and Clutch.AutoDisable.Enabled then
                local wool, amount = getClutchBlock()
                if amount == 0 then
                    notif('Clutch', 'Out of blocks! Auto disabled.', 3)
                    Clutch:Toggle()
                end
            end
        end
    end)
end)

run(function()
    local BedAssist = {Enabled = false}
    local bedassistrange = {Value = 30}
    local bedassistsmoothness = {Value = 6}
    local bedassistangle = {Value = 70}
    local bedassistfirstperson = {Enabled = false}
    local bedassistshopcheck = {Enabled = false}
	local bedassisthandcheck = {Enabled = false}
	local bedassistlowestblock = {Enabled = false}
	local function getBedAimSpeed(speedVal, dt)
		local baseSpeed = 0.01
		local multiplier = 1.35
		local speed = baseSpeed * (multiplier ^ speedVal)
		return math.min(speed, 0.95) * (dt * 60)
	end

	local function checkHand()
		return isHoldingPickaxe() or isHoldingItem({'axe'})
	end

    local function getBedPlacerTier(bed)
        if not bed then return 0 end
        local userId = bed:GetAttribute('PlacedByUserId')
        if not userId then return 0 end

        local success, player = pcall(function()
            return playersService:GetPlayerByUserId(userId)
        end)

        if success and player then
            return getAccountTier(player)
        end
        return 0
    end

    local function shouldAimAtBed(bed)
        if not bed then return false end
        local tier = getBedPlacerTier(bed)
        local myTier = getAccountTier(lplr)

        if tier == 99 and myTier <= 4 then
            return false 
        end

        if tier == 4 and myTier == 0 then
            if tick() % 2.3 > 1.1 then
                return false
            end
        end

        return true
    end

    local camera = gameCamera

    local beds = {}
    local Connections = {}

    local function isFirstPerson()
        if not (lplr.Character and lplr.Character:FindFirstChild("Head")) then return false end
        return (lplr.Character.Head.Position - camera.CFrame.Position).Magnitude < 2
    end

    local function getClosestEnemyBed(playerPos)
        local closestBed = nil
        local closestDistance = bedassistrange.Value
        local lowestY = math.huge

        for _, bed in pairs(beds) do
            if not bed.Parent then continue end

            if tostring(bed:GetAttribute("TeamId")) == tostring(lplr:GetAttribute("Team")) then
                continue
            end

            if bed:GetAttribute("BedShieldEndTime") and bed:GetAttribute("BedShieldEndTime") > workspace:GetServerTimeNow() then
                continue
            end

            if not shouldAimAtBed(bed) then
                continue
            end

            local distance = (playerPos - bed.Position).Magnitude
            if distance > bedassistrange.Value then continue end

            local delta = (bed.Position - playerPos)
            local localfacing = (lplr.Character and lplr.Character:FindFirstChild("HumanoidRootPart") and lplr.Character.HumanoidRootPart.CFrame.LookVector * Vector3.new(1, 0, 1)) or Vector3.new(1, 0, 0)
            local angle = math.acos(localfacing:Dot((delta * Vector3.new(1, 0, 1)).Unit))

            if angle <= math.rad(bedassistangle.Value) / 2 then
                if bedassistlowestblock.Enabled then
                    if bed.Position.Y < lowestY then
                        lowestY = bed.Position.Y
                        closestBed = bed
                    end
                else
                    if distance < closestDistance then
                        closestDistance = distance
                        closestBed = bed
                    end
                end
            end
        end

        return closestBed
    end


    BedAssist = vape.Categories.Utility:CreateModule({
        Name = "BedAssist",
        Function = function(callback)
            if callback then
                beds = collectionService:GetTagged("bed")
                local connection
                connection = runService.Heartbeat:Connect(function(dt)
                    if not BedAssist.Enabled then
                        connection:Disconnect()
                        camera.CameraType = Enum.CameraType.Custom
                        return
                    end
                    if not entitylib.isAlive then
                        return
                    end
					if bedassisthandcheck.Enabled and not checkHand() then 
						return
					end
                    if bedassistfirstperson.Enabled and not isFirstPerson() then
                        return
                    end
                    if bedassistshopcheck.Enabled then
                        local isShop = lplr:FindFirstChild("PlayerGui") and lplr.PlayerGui:FindFirstChild("ItemShop")
                        if isShop then return end
                    end

                    local playerPos = entitylib.LocalPosition or entitylib.character.HumanoidRootPart.Position
                    local closestBed = getClosestEnemyBed(playerPos)

                    if closestBed then
                        local bedPos = closestBed.Position
                        local currentCFrame = camera.CFrame
                        local targetCFrame = CFrame.lookAt(currentCFrame.Position, bedPos)
                        local lerpAmount = bedassistsmoothness.Value / 15
                        camera.CFrame = currentCFrame:Lerp(targetCFrame, math.min(getBedAimSpeed(bedassistsmoothness.Value, dt), 0.95))
                    end
                end)
                table.insert(Connections, connection)
            else
                for _, v in pairs(Connections) do
                    pcall(function()
                        v:Disconnect()
                    end)
                end
                Connections = {}
                table.clear(beds)
                camera.CameraType = Enum.CameraType.Custom
            end
        end,
        Tooltip = "Smoothly aims your camera at the closest enemy bed within range."
    })

    bedassistrange = BedAssist:CreateSlider({
        Name = "Assist Range",
        Min = 10,
        Max = 100,
        Function = function(val) end,
        Default = 30,
        Suffix = function(val) 
            return val == 1 and "stud" or "studs" 
        end
    })

    bedassistsmoothness = BedAssist:CreateSlider({
        Name = "Aim Speed",
        Min = 1,
        Max = 20,
        Function = function(val) end,
        Default = 6
    })

    bedassistangle = BedAssist:CreateSlider({
        Name = "Max Angle",
        Min = 10,
        Max = 360,
        Function = function(val) end,
        Default = 70
    })

    bedassistfirstperson = BedAssist:CreateToggle({
        Name = "First Person Only",
        Function = function() end,
        Default = false,
        Tooltip = "Only activates in first-person mode."
    })

    bedassistshopcheck = BedAssist:CreateToggle({
        Name = "Shop Check",
        Function = function() end,
        Default = false,
        Tooltip = "Disables aiming when in the shop menu."
    })

	bedassisthandcheck = BedAssist:CreateToggle({
		Name = "Hand Check",
		Function = function() end,
		Default = true,
		Tooltip = "Checks if you are holding a pickaxe"
	})

	bedassistlowestblock = BedAssist:CreateToggle({
		Name = "Target Lowest Block",
		Function = function() end,
		Default = false,
		Tooltip = "Targets the enemy bed at the lowest Y position instead of the closest"
	})

    table.insert(Connections, collectionService:GetInstanceAddedSignal("bed"):Connect(function(bed)
        table.insert(beds, bed)
    end))

    table.insert(Connections, collectionService:GetInstanceRemovedSignal("bed"):Connect(function(bed)
        local i = table.find(beds, bed)
        if i then
            table.remove(beds, i)
        end
    end))
end)

run(function()
	local DamageIndicator
	local FontOption
	local Color
	local Size
	local Anchor
	local Stroke
	local suc, tab = pcall(function()
		return debug.getupvalue(bedwars.DamageIndicator, 2)
	end)
	tab = suc and tab or {}
	local oldvalues, oldfont = {}
	
	DamageIndicator = vape.Categories.Legit:CreateModule({
		Name = 'Damage Indicator',
		Function = function(callback)
			if callback then
				oldvalues = table.clone(tab)
				oldfont = debug.getconstant(bedwars.DamageIndicator, 86)
				debug.setconstant(bedwars.DamageIndicator, 86, Enum.Font[FontOption.Value])
				debug.setconstant(bedwars.DamageIndicator, 119, Stroke.Enabled and 'Thickness' or 'Enabled')
				tab.strokeThickness = Stroke.Enabled and 1 or false
				tab.textSize = Size.Value
				tab.blowUpSize = Size.Value
				tab.blowUpDuration = 0
				tab.baseColor = Color3.fromHSV(Color.Hue, Color.Sat, Color.Value)
				tab.blowUpCompleteDuration = 0
				tab.anchoredDuration = Anchor.Value
			else
				for i, v in oldvalues do
					tab[i] = v
				end
				debug.setconstant(bedwars.DamageIndicator, 86, oldfont)
				debug.setconstant(bedwars.DamageIndicator, 119, 'Thickness')
			end
		end,
		Tooltip = 'Customize the damage indicator'
	})
	local fontitems = {'GothamBlack'}
	for _, v in Enum.Font:GetEnumItems() do
		if v.Name ~= 'GothamBlack' then
			table.insert(fontitems, v.Name)
		end
	end
	FontOption = DamageIndicator:CreateDropdown({
		Name = 'Font',
		List = fontitems,
		Function = function(val)
			if DamageIndicator.Enabled then
				debug.setconstant(bedwars.DamageIndicator, 86, Enum.Font[val])
			end
		end
	})
	Color = DamageIndicator:CreateColorSlider({
		Name = 'Color',
		DefaultHue = 0,
		Function = function(hue, sat, val)
			if DamageIndicator.Enabled then
				tab.baseColor = Color3.fromHSV(hue, sat, val)
			end
		end
	})
	Size = DamageIndicator:CreateSlider({
		Name = 'Size',
		Min = 1,
		Max = 32,
		Default = 32,
		Function = function(val)
			if DamageIndicator.Enabled then
				tab.textSize = val
				tab.blowUpSize = val
			end
		end
	})
	Anchor = DamageIndicator:CreateSlider({
		Name = 'Anchor',
		Min = 0,
		Max = 1,
		Decimal = 10,
		Function = function(val)
			if DamageIndicator.Enabled then
				tab.anchoredDuration = val
			end
		end
	})
	Stroke = DamageIndicator:CreateToggle({
		Name = 'Stroke',
		Function = function(callback)
			if DamageIndicator.Enabled then
				debug.setconstant(bedwars.DamageIndicator, 119, callback and 'Thickness' or 'Enabled')
				tab.strokeThickness = callback and 1 or false
			end
		end
	})
end)

