										healTarget = plr.Character
									})
									task.wait(1 / Delay.GetRandomValue())
								else
									task.wait(1 / Delay.GetRandomValue())
									continue
								end
							else
								continue
							end
						else
							continue
						end
					end
					task.wait(1 / UpdateRate.Value)
				until MelodyExploit.Enabled
			end
		end
	})
