		rebellion_leader = function()
			local last = 0
			local abilityCooldown = 0.02
		
			repeat
				if not entitylib.isAlive then task.wait(0.1); continue end

				local plr = entitylib.EntityPosition({
					Range = Legit.Enabled and 15 or 25,
					Part = "RootPart",
