							if days > 0 then
								table.insert(parts, days .. (days == 1 and " day" or " days"))
							end

							if daysTotal <= 1 then
								table.insert(parts, hours .. (hours == 1 and " hour" or " hours"))
								table.insert(parts, minutes .. " minutes")
							end

							local result = table.concat(parts, ", ")
							txt.Text = 'Account age: '..result
						end)
					end

