run(function()
    local BedProtector
    local PlaceRange
    local Blacklist
    local Mode
    local Smart
    local Switch
    local Layers
    local AutoPatch
    local ProtectedLayers
    local PlacementSpeed

    local function getBedNear()
        local localPosition = entitylib.isAlive and entitylib.character.RootPart.Position or Vector3.zero
        for _, v in collectionService:GetTagged('bed') do
            if
                (localPosition - v.Position).Magnitude < 14
                and v:GetAttribute('Team' .. (lplr:GetAttribute('Team') or -1) .. 'NoBreak')
            then
                return v
            end
        end
        return nil
    end

    local function getBlocks()
        local blocks = {}
        for _, item in store.inventory.inventory.items do
            local block = bedwars.ItemMeta[item.itemType].block
            if
                block and not table.find(Blacklist.ListEnabled, item.itemType:find('wool') and 'wool' or item.itemType)
            then
                table.insert(blocks, { item.itemType, block.health, item.tool })
            end
        end
        table.sort(blocks, function(a, b)
            return a[2] > b[2]
        end)
        return blocks
    end

    local function getPyramid(size, grid)
        local positions = {}
        for h = size, 0, -1 do
            for w = h, 0, -1 do
                table.insert(positions, Vector3.new(w, (size - h), ((h + 1) - w)) * grid)
                table.insert(positions, Vector3.new(w * -1, (size - h), ((h + 1) - w)) * grid)
                table.insert(positions, Vector3.new(w, (size - h), (h - w) * -1) * grid)
                table.insert(positions, Vector3.new(w * -1, (size - h), (h - w) * -1) * grid)
            end
        end
        return positions
    end

    local function isEnemy(player)
        if not player then return false end
        local myTeam = lplr:GetAttribute('Team')
        return player:GetAttribute('Team') ~= myTeam
    end

    local function isWithinProtectedLayers(worldPos, bed)
        if not bed then return false end
        local relPos = bed.CFrame:PointToObjectSpace(worldPos)
        local gx = math.floor(relPos.X / 3 + 0.5)
        local gy = math.floor(relPos.Y / 3 + 0.5)
        local gz = math.floor(relPos.Z / 3 + 0.5)
        local maxLayer = ProtectedLayers.Value
        for layer = 1, maxLayer do
            for _, pos in getPyramid(layer, 3) do
                local px = math.floor(pos.X / 3 + 0.5)
                local py = math.floor(pos.Y / 3 + 0.5)
                local pz = math.floor(pos.Z / 3 + 0.5)
                if px == gx and py == gy and pz == gz then
                    return true
                end
            end
        end
        return false
    end

    BedProtector = vape.Categories.World:CreateModule({
        Name = 'Draco X2',
        Function = function(callback)
            if callback then
                BedProtector:Clean(vapeEvents.BreakBlockEvent.Event:Connect(function(data)
                    if not BedProtector.Enabled then return end
                    if not AutoPatch.Enabled then return end
                    if not entitylib.isAlive then return end
                    if not isEnemy(data.player) then return end

                    local worldPos = data.blockRef.blockPosition * 3
                    local bed = getBedNear()
                    if not bed then return end
                    if (worldPos - bed.Position).Magnitude > PlaceRange.Value then return end
                    if not isWithinProtectedLayers(worldPos, bed) then return end
                    if getPlacedBlock(worldPos) then return end

                    local blocks = getBlocks()
                    if #blocks == 0 then return end
                    local block = blocks[1]

                    task.spawn(function()
                        if PlacementSpeed.Value > 0 then
                            task.wait(PlacementSpeed.Value / 1000)
                        end

                        if getPlacedBlock(worldPos) then return end
                        if (entitylib.character.RootPart.Position - worldPos).Magnitude > PlaceRange.Value then return end

                        local old = store.hand and store.hand.tool and getHotbar(store.hand.tool) or nil
                        local switched = false

                        if Switch.Enabled then
                            local hotbar = getHotbar(block[3])
                            if hotbar and hotbarSwitch(hotbar) then
                                switched = true
                                task.wait()
                            end
                        end

                        bedwars.placeBlock(worldPos, block[1], false)

                        if switched and old then
                            task.wait()
                            hotbarSwitch(old)
                        end
                    end)
                end))

                repeat
                    local bed = getBedNear()
                    if bed then
                        for i, block in getBlocks() do
                            if i > Layers.Value then
                                break
                            end
                            local switch, old = Switch.Enabled, store.hand and store.hand.tool and getHotbar(store.hand.tool) or nil
                            local hotbar = nil

                            if switch then
                                hotbar = getHotbar(block[3])
                            end

                            for _, pos in getPyramid(i, 3) do
                                if not BedProtector.Enabled then
                                    break
                                end
                                pos = (bed.CFrame * CFrame.new(pos)).Position
                                if getPlacedBlock(pos) then
                                    continue
                                end
                                if (entitylib.character.RootPart.Position - pos).Magnitude > PlaceRange.Value then
                                    continue
                                end
                                if hotbar and hotbarSwitch(hotbar) then
                                    task.wait()
                                end
                                task.spawn(bedwars.placeBlock, pos, block[1], false)
                                task.wait(0.1)
                            end

                            if switch and old and hotbarSwitch(old) then
                                task.wait()
                            end
                        end
                    else
                        if Mode.Value == 'On Key' then
                            notif('Draco X2', 'Unable to locate bed', 5)
                            BedProtector:Toggle()
                        end
                    end
                    task.wait(0.5)
                    if Mode.Value == 'On Key' then
                        BedProtector:Toggle()
                        break
                    end
                until not BedProtector.Enabled
            end
        end,
        Tooltip = 'Automatically places and defends blocks around the bed.'
    })

    Mode = BedProtector:CreateDropdown({
        Name = 'Mode',
        List = {'Toggle', 'On Key'},
        Default = 'Toggle',
        Function = function(val)
            if Smart then
                Smart.Object.Visible = val == 'Toggle'
            end
        end,
    })
    Blacklist = BedProtector:CreateTextList({
        Name = 'Blacklist',
        Default = {'siege_tnt', 'tnt'},
    })
    PlaceRange = BedProtector:CreateSlider({
        Name = 'Place Range',
        Min = 1,
        Max = 30,
        Default = 15,
    })
    Layers = BedProtector:CreateSlider({
        Name = 'Layers',
        Min = 1,
        Max = 8,
        Default = 3,
        Suffix = function(v) return v == 1 and 'layer' or 'layers' end,
        Tooltip = 'How many pyramid layers to build around the bed; set to 1 to only build the closest layer'
    })
    Switch = BedProtector:CreateToggle({Name = 'Auto Switch'})
    Smart = BedProtector:CreateToggle({Name = 'Smart', Default = true})
    AutoPatch = BedProtector:CreateToggle({
        Name = 'AutoPatch',
        Default = false,
        Tooltip = 'When enabled, automatically replaces blocks broken by enemies within the protected layers'
    })
    ProtectedLayers = BedProtector:CreateSlider({
        Name = 'Protected Layers',
        Min = 1,
        Max = 8,
        Default = 2,
        Suffix = function(v) return v == 1 and 'layer' or 'layers' end,
        Tooltip = 'How many pyramid layers AutoPatch will monitor and rebuild when broken by enemies'
    })
    PlacementSpeed = BedProtector:CreateSlider({
        Name = 'Placement Speed',
        Min = 0,
        Max = 500,
        Default = 100,
        Suffix = 'ms',
        Tooltip = 'Delay in milliseconds before AutoPatch places a replacement block; 0 for instant'
    })
end)

run(function()
	local AutoSuffocate
	local Range
	local LimitItem
	
	local function fixPosition(pos)
		return bedwars.BlockController:getBlockPosition(pos) * 3
	end
	
	AutoSuffocate = vape.Categories.World:CreateModule({
		Name = 'AutoSuffocate',
		Function = function(callback)
			if callback then
				repeat
					local item = store.hand.toolType == 'block' and store.hand.tool.Name or not LimitItem.Enabled and getWool()
	
					if item then
						local plrs = entitylib.AllPosition({
							Part = 'RootPart',
							Range = Range.Value,
							Players = true
						})
	
						for _, ent in plrs do
							local needPlaced = {}
	
							for _, side in Enum.NormalId:GetEnumItems() do
								side = Vector3.fromNormalId(side)
								if side.Y ~= 0 then continue end
	
								side = fixPosition(ent.RootPart.Position + side * 2)
								if not getPlacedBlock(side) then
									table.insert(needPlaced, side)
								end
							end
	
							if #needPlaced < 3 then
								table.insert(needPlaced, fixPosition(ent.Head.Position))
								table.insert(needPlaced, fixPosition(ent.RootPart.Position - Vector3.new(0, 1, 0)))
	
								for _, pos in needPlaced do
									if not getPlacedBlock(pos) then
										task.spawn(bedwars.placeBlock, pos, item)
										break
									end
								end
							end
						end
					end
	
					task.wait(0.09)
				until not AutoSuffocate.Enabled
			end
		end,
		Tooltip = 'Places blocks on nearby confined entities'
	})
	Range = AutoSuffocate:CreateSlider({
		Name = 'Range',
		Min = 1,
		Max = 20,
		Default = 20,
		Suffix = function(val)
			return val == 1 and 'stud' or 'studs'
		end
	})
	LimitItem = AutoSuffocate:CreateToggle({
		Name = 'Limit to Items',
		Default = true
	})
end)
	
run(function()
	local funni
	local last = os.clock()
	funni = vape.Categories.Blatant:CreateModule({
		Name = 'Cake',
		Tooltip = 'Gives you a sugar rush to dominate your opponents!',
		Function = function(callback)
			if callback then
				repeat
					if os.clock() - last >= 1 then
					game:GetService("ReplicatedStorage").rbxts_include.node_modules["@rbxts"].net.out._NetManaged.PlayerEatCake:FireServer({block = game.ReplicatedStorage.Items.cake_one})
						last = os.clock()
					end
					task.wait()
				until (not funni.Enabled)
			end
		end
	})
end)

run(function()
	local AutoXP;

	AutoXP = vape.Categories.Utility:CreateModule({
		Name = 'AutoXP',
		Function = function(callback)
			if callback then
				repeat task.wait(1) until bedwars.Knit.Controllers.MatchController:getMatchState() == 1

				local chests = {}
				for _, value in workspace:GetChildren() do
					if value.Name == 'chest' then
						table.insert(chests, value)
					end
				end

				AutoXP:Clean(workspace.ChildAdded:Connect(function(child)
					if child.Name == 'chest' then
						table.insert(chests, child)
					end
				end))

				local nearestChest = (function()
					local nearest, dist = nil, math.huge
					for index, value in chests do
						if lplr:DistanceFromCharacter(value.Position) < dist then
							dist = lplr:DistanceFromCharacter(value.Position)
							nearest = value
						end
					end

					return nearest
				end)()

				tweenService:Create(entitylib.character.RootPart, TweenInfo.new(0.5), {
					CFrame = nearestChest and nearestChest.CFrame + Vector3.new(0, 5, 0) or entitylib.character.RootPart.CFrame
				}):Play()
				local start = tick()

				repeat task.wait(2)
					mouse1click()
				until (tick() - start) > 30 or not AutoXP.Enabled

				if AutoXP.Enabled then
					Client:Get('ResetCharacter'):SendToServer()
					bedwars.QueueController:joinQueue(store.queueType)
				end
			end
		end
	})
end)

run(function()
    local FastKillaura, Targets, Sort, Range, UpdateRate, AngleSlider, MaxTargets
    local Mouse, Swing, GUI, BoxColor, ParticleTexture, ParticleColor1, ParticleColor2
    local ParticleSize, Face, Animation, AnimationMode, AnimationSpeed, AnimationTween
    local Limit, LegitAura, Sync
    local Particles, Boxes = {}, {}
    local anims, AnimDelay, AnimTween, armC0 = vape.Libraries.auraanims, tick()
    local AttackRemote = {FireServer = function() end}
 
    task.spawn(function()
        AttackRemote = bedwars.Client:Get(remotes.AttackEntity).instance
    end)
 
    local function calculateRange(range)
        return math.clamp(range, 1, 20) * 1.5
    end
 
    local function performAttack(sword, meta, target, selfpos)
        local delta = (target.RootPart.Position - selfpos)
        local dir = CFrame.lookAt(selfpos, target.RootPart.Position).LookVector
        local pos = selfpos + dir * math.max(delta.Magnitude - 2, 0)
 
        local attackData = {
            weapon = sword.tool,
            chargedAttack = {
                chargeRatio = 1
            },
            entityInstance = target.Character,
            validate = {
                raycast = {
                    cameraPosition = {value = pos},
                    cursorDirection = {value = dir}
                },
                targetPosition = {value = target.RootPart.Position},
                selfPosition = {value = pos}
            }
        }
 
        bedwars.SwordController.lastAttack = workspace:GetServerTimeNow()
        store.attackReach = delta.Magnitude
        store.attackReachUpdate = tick() + 1
 
        for i = 1, 158 do
            AttackRemote:FireServer(attackData)
            task.wait(0.01)
        end
    end
 
    local function getAttackData()
        if Mouse.Enabled and not inputService:IsMouseButtonPressed(0) then 
            return false 
        end
 
        if GUI.Enabled and bedwars.AppController:isLayerOpen(bedwars.UILayers.MAIN) then 
            return false 
        end
 
        local sword = Limit.Enabled and store.hand or store.tools.sword
        if not sword or not sword.tool then 
            return false 
        end
 
        local meta = bedwars.ItemMeta[sword.tool.Name]
        if Limit.Enabled and (store.hand.toolType ~= 'sword' or bedwars.DaoController.chargingMaid) then 
            return false 
        end
 
        if LegitAura.Enabled and (tick() - bedwars.SwordController.lastSwing) > 0.1 then 
            return false 
        end
 
        return sword, meta
    end
 
    local function playAttackAnimation(meta)
        if not Swing.Enabled and AnimDelay <= tick() and not LegitAura.Enabled then
            AnimDelay = tick() + (meta.sword.respectAttackSpeedForEffects and meta.sword.attackSpeed or (Sync.Enabled and 0.24 or 0.14))
            bedwars.SwordController:playSwordEffect(meta, 0)
 
            if meta.displayName:find(' Scythe') then
                bedwars.ScytheController:playLocalAnimation()
            end
        end
    end
 
    local function getTargets(range)
        return entitylib.AllPosition({
            Range = calculateRange(range),
            Wallcheck = Targets.Walls.Enabled or nil,
            Part = 'RootPart',
            Players = Targets.Players.Enabled,
            NPCs = Targets.NPCs.Enabled,
            Limit = MaxTargets.Value,
            Sort = sortmethods[Sort.Value]
        })
    end
 
    FastKillaura = vape.Categories.Blatant:CreateModule({
        Name = 'FastKillaura',
        Function = function(callback)
            if callback then
                if inputService.TouchEnabled then
                    pcall(function()
                        lplr.PlayerGui.MobileUI['2'].Visible = Limit.Enabled
                    end)
                end
 
                if Animation.Enabled then
                    local fake = {
                        Controllers = {
                            ViewmodelController = {
                                isVisible = function()
                                    return not Attacking
                                end,
                                playAnimation = function(...)
                                    if not Attacking then
                                        bedwars.ViewmodelController:playAnimation(select(2, ...))
                                    end
                                end
                            }
                        }
                    }
                    debug.setupvalue(bedwars.SwordController.playSwordEffect, 6, fake)
                    debug.setupvalue(bedwars.ScytheController.playLocalAnimation, 3, fake)
 
                    task.spawn(function()
                        local started = false
                        repeat
                            if Attacking then
                                if not armC0 then
                                    armC0 = gameCamera.Viewmodel.RightHand.RightWrist.C0
                                end
 
                                local first = not started
                                started = true
 
                                if AnimationMode.Value == 'Random' then
                                    anims.Random = {{CFrame = CFrame.Angles(math.rad(math.random(1, 360)), math.rad(math.random(1, 360)), math.rad(math.random(1, 360))), Time = 0.12}}
                                end
 
                                for _, v in anims[AnimationMode.Value] do
                                    AnimTween = tweenService:Create(gameCamera.Viewmodel.RightHand.RightWrist, TweenInfo.new(first and (AnimationTween.Enabled and 0.001 or 0.1) or v.Time / AnimationSpeed.Value, Enum.EasingStyle.Linear), {
                                        C0 = armC0 * v.CFrame
                                    })
                                    AnimTween:Play()
                                    AnimTween.Completed:Wait()
                                    first = false
                                    if (not FastKillaura.Enabled) or (not Attacking) then break end
                                end
                            elseif started then
                                started = false
                                AnimTween = tweenService:Create(gameCamera.Viewmodel.RightHand.RightWrist, TweenInfo.new(AnimationTween.Enabled and 0.001 or 0.3, Enum.EasingStyle.Exponential), {
                                    C0 = armC0
                                })
                                AnimTween:Play()
                            end
 
                            if not started then
                                task.wait(0.01)
                            end
                        until (not FastKillaura.Enabled) or (not Animation.Enabled)
                    end)
                end
 
                repeat
                    local attacked, sword, meta = {}, getAttackData()
                    Attacking = false
                    store.KillauraTarget = nil
 
                    if sword then
                        local plrs = getTargets(Range.Value)
                        if #plrs > 0 then
                            switchItem(sword.tool, 0)
                            local selfpos = entitylib.character.RootPart.Position
                            local localfacing = entitylib.character.RootPart.CFrame.LookVector * Vector3.new(1, 0, 1)
 
                            for _, v in plrs do
                                local delta = (v.RootPart.Position - selfpos)
                                if delta.Magnitude <= calculateRange(Range.Value) then
                                    local angle = math.acos(localfacing:Dot((delta * Vector3.new(1, 0, 1)).Unit))
                                    if angle <= (math.rad(AngleSlider.Value) / 2) then
                                        table.insert(attacked, v)
                                        targetinfo.Targets[v] = tick() + 1
 
                                        if not Attacking then
                                            Attacking = true
                                            store.KillauraTarget = v
                                            playAttackAnimation(meta)
                                        end
 
                                        performAttack(sword, meta, v, selfpos)
                                    end
                                end
                            end
                        end
                    end
 
                    for i, v in Boxes do
                        v.Adornee = attacked[i] and attacked[i].RootPart or nil
                        if v.Adornee then
                            v.Color3 = Color3.fromHSV(BoxColor.Hue, BoxColor.Sat, BoxColor.Value)
                            v.Transparency = 1 - BoxColor.Opacity
                        end
                    end
 
                    for i, v in Particles do
                        v.Position = attacked[i] and attacked[i].RootPart.Position or Vector3.new(9e9, 9e9, 9e9)
                        v.Parent = attacked[i] and gameCamera or nil
                    end
 
                    if Face.Enabled and attacked[1] then
                        local vec = attacked[1].RootPart.Position * Vector3.new(1, 0, 1)
                        entitylib.character.RootPart.CFrame = CFrame.lookAt(entitylib.character.RootPart.Position, Vector3.new(vec.X, entitylib.character.RootPart.Position.Y, vec.Z))
                    end
 
                    task.wait(0.01)
                until not FastKillaura.Enabled
            else
                store.KillauraTarget = nil
                for _, v in Boxes do
                    v.Adornee = nil
                end
                for _, v in Particles do
                    v.Parent = nil
                end
                if inputService.TouchEnabled then
                    pcall(function()
                        lplr.PlayerGui.MobileUI['2'].Visible = true
                    end)
                end
                debug.setupvalue(bedwars.SwordController.playSwordEffect, 6, bedwars.Knit)
                debug.setupvalue(bedwars.ScytheController.playLocalAnimation, 3, bedwars.Knit)
                Attacking = false
                if armC0 then
                    AnimTween = tweenService:Create(gameCamera.Viewmodel.RightHand.RightWrist, TweenInfo.new(AnimationTween.Enabled and 0.001 or 0.3, Enum.EasingStyle.Exponential), {
                        C0 = armC0
                    })
                    AnimTween:Play()
                end
            end
        end,
        Tooltip = 'Attack players around you\nwithout aiming at them.'
    })
 
    Targets = FastKillaura:CreateTargets({
        Players = true,
        NPCs = true,
        Walls = true
    })
 
    local methods = {'Damage', 'Distance'}
    for i in sortmethods do
        if not table.find(methods, i) then
            table.insert(methods, i)
        end
    end
 
    Range = FastKillaura:CreateSlider({
        Name = 'Attack range',
        Min = 1,
        Max = 20,
        Default = 18,
        Suffix = function(val)
            return val == 1 and 'stud' or 'studs'
        end
    })
 
    AngleSlider = FastKillaura:CreateSlider({
        Name = 'Max angle',
        Min = 1,
        Max = 360,
        Default = 360
    })
 
    UpdateRate = FastKillaura:CreateSlider({
        Name = 'Update rate',
        Min = 1,
        Max = 120,
        Default = 60,
        Suffix = 'hz'
    })
 
    MaxTargets = FastKillaura:CreateSlider({
        Name = 'Max targets',
        Min = 1,
        Max = 5,
        Default = 5
    })
 
    Sort = FastKillaura:CreateDropdown({
        Name = 'Target Mode',
        List = methods
    })
 
    Mouse = FastKillaura:CreateToggle({Name = 'Require mouse down'})
    Swing = FastKillaura:CreateToggle({Name = 'No Swing'})
    GUI = FastKillaura:CreateToggle({Name = 'GUI check'})
 
    FastKillaura:CreateToggle({
        Name = 'Show target',
        Function = function(callback)
            BoxColor.Object.Visible = callback
            if callback then
                for i = 1, 10 do
                    local box = Instance.new('BoxHandleAdornment')
                    box.Adornee = nil
                    box.AlwaysOnTop = true
                    box.Size = Vector3.new(3, 5, 3)
                    box.CFrame = CFrame.new(0, -0.5, 0)
                    box.ZIndex = 0
                    box.Parent = vape.gui
                    Boxes[i] = box
                end
            else
                for _, v in Boxes do
                    v:Destroy()
                end
                table.clear(Boxes)
            end
        end
    })
 
    BoxColor = FastKillaura:CreateColorSlider({
        Name = 'Attack Color',
        Darker = true,
        DefaultOpacity = 0.5,
        Visible = false
    })
 
    Face = FastKillaura:CreateToggle({Name = 'Face target'})
 
    Animation = FastKillaura:CreateToggle({
        Name = 'Custom Animation',
        Function = function(callback)
            AnimationMode.Object.Visible = callback
            AnimationTween.Object.Visible = callback
            AnimationSpeed.Object.Visible = callback
            if FastKillaura.Enabled then
                FastKillaura:Toggle()
                FastKillaura:Toggle()
            end
        end
    })
 
    local animnames = {}
    for i in anims do
        table.insert(animnames, i)
    end
 
    AnimationMode = FastKillaura:CreateDropdown({
        Name = 'Animation Mode',
        List = animnames,
        Darker = true,
        Visible = false
    })
 
    AnimationSpeed = FastKillaura:CreateSlider({
        Name = 'Animation Speed',
        Min = 0,
        Max = 2,
        Default = 1,
        Decimal = 10,
        Darker = true,
        Visible = false
    })
 
    AnimationTween = FastKillaura:CreateToggle({
        Name = 'No Tween',
        Darker = true,
        Visible = false
    })
 
    Limit = FastKillaura:CreateToggle({
        Name = 'Limit to items',
        Function = function(callback)
            if inputService.TouchEnabled and FastKillaura.Enabled then
                pcall(function()
                    lplr.PlayerGui.MobileUI['2'].Visible = callback
                end)
            end
        end,
        Tooltip = 'Only attacks when the sword is held'
    })
 
    LegitAura = FastKillaura:CreateToggle({
        Name = 'Swing only',
        Tooltip = 'Only attacks while swinging manually'
    })
 
    Sync = FastKillaura:CreateToggle({
        Name = 'Synced Animation',
        Tooltip = 'Plays animation with hit attempt'
    })
 
end)


local run = function(func)
	func()
end

run(function()
	local TeamCrateChecker
	local UpdateSpeed
	local ShowDetails
	local Reference = {}
	
	TeamCrateChecker = vape.Categories.Utility:CreateModule({
		Name = 'TeamCrateChecker',
		Function = function(callback)
			if callback then
				repeat
					local crate = workspace:GetChildren()[50]
					if not crate then
						task.wait(UpdateSpeed.Value or 1)
						continue
					end
					
					local items = {}
					local itemTypes = {}
					
					-- Scan crate contents
					for _, item in ipairs(crate:GetDescendants()) do
						if item:IsA("Part") or item:IsA("Model") then
							local itemName = item.Name
							local itemType = "Unknown"
							
							-- Categorize items
							if itemName:lower():find("ammo") then
								itemType = "Ammunition"
							elseif itemName:lower():find("gun") or itemName:lower():find("rifle") or itemName:lower():find("weapon") then
								itemType = "Weapon"
							elseif itemName:lower():find("health") or itemName:lower():find("med") then
								itemType = "Medical"
							elseif itemName:lower():find("grenade") or itemName:lower():find("explosive") then
								itemType = "Explosive"
							elseif itemName:lower():find("armor") or itemName:lower():find("shield") then
								itemType = "Armor"
							end
							
							if not itemTypes[itemType] then
								itemTypes[itemType] = 0
							end
							itemTypes[itemType] = itemTypes[itemType] + 1
							table.insert(items, {Name = itemName, Type = itemType})
						end
					end
					
					-- Build display string
					local display = "Crate Items: "
					for itemType, count in pairs(itemTypes) do
						display = display .. itemType .. "(" .. count .. ") "
					end
					
					if ShowDetails.Enabled then
						print("[TeamCrateChecker] " .. display)
						for _, item in ipairs(items) do
							print("  - " .. item.Name .. " [" .. item.Type .. "]")
						end
					end
					
					task.wait(UpdateSpeed.Value or 1)
				until not TeamCrateChecker.Enabled
			end
		end,
		Tooltip = 'Displays contents of the team crate'
	})
	
	UpdateSpeed = TeamCrateChecker:CreateSlider({
		Name = 'Update Speed',
		Min = 0.5,
		Max = 5,
		Default = 1,
		Decimal = 2,
		Suffix = 's'
	})
	
	ShowDetails = TeamCrateChecker:CreateToggle({
		Name = 'Show Details',
		Default = false,
		Tooltip = 'Prints detailed item list to console'
	})
end)

run(function()
	local AutoVoidDrop
	local OwlCheck
	local DropToggles = {
		iron = nil,
		diamond = nil,
		emerald = nil,
		gold = nil
	}
	local cachedLowestPoint
	local Delay

	
	AutoVoidDrop = vape.Categories.Utility:CreateModule({
		Name = 'AutoVoidDrop',
		Function = function(callback)
			if callback then
				repeat task.wait() until store.matchState ~= 0 or (not AutoVoidDrop.Enabled)
				if not AutoVoidDrop.Enabled then return end

				cachedLowestPoint = math.huge
				for _, v in pairs(store.blocks) do
					local point = (v.Position.Y - (v.Size.Y / 2)) - 50
					if point < cachedLowestPoint then
						cachedLowestPoint = point
					end
				end

				repeat
					if entitylib.isAlive then
						local root = entitylib.character.RootPart
						if root.Position.Y < cachedLowestPoint and (lplr.Character:GetAttribute('InflatedBalloons') or 0) <= 0 and not getItem('balloon') then
							if not OwlCheck.Enabled or not root:FindFirstChild('OwlLiftForce') then
								for itemType, toggle in pairs(DropToggles) do
									if toggle.Enabled then
										local item = getItem(itemType)
										if item then
											task.wait(Delay.Value)
											local dropped = bedwars.Client:Get(remotes.DropItem):CallServer({
												item = item.tool,
												amount = item.amount
											})
		
											if dropped then
												dropped:SetAttribute('ClientDropTime', tick() + 100)
											end
										end
									end
								end
								break
							end
						end
					end

					task.wait(0.1)
				until not AutoVoidDrop.Enabled
			end
		end,
		Tooltip = 'Drops resources when you fall into the void'
	})
	
	OwlCheck = AutoVoidDrop:CreateToggle({
		Name = 'Owl check',
		Default = true,
		Tooltip = 'Refuses to drop items if being picked up by an owl'
	})
	DropToggles.iron = AutoVoidDrop:CreateToggle({
		Name = 'Drop Iron',
		Tooltip = 'Drop iron when falling into void',
		Default = true
	})
	DropToggles.diamond = AutoVoidDrop:CreateToggle({
		Name = 'Drop Diamond',
		Tooltip = 'Drop diamonds when falling into void',
		Default = true
	})
	DropToggles.emerald = AutoVoidDrop:CreateToggle({
		Name = 'Drop Emerald',
		Tooltip = 'Drop emeralds when falling into void',
		Default = true
	})
	DropToggles.gold = AutoVoidDrop:CreateToggle({
		Name = 'Drop Gold',
		Tooltip = 'Drop gold when falling into void',
		Default = true
	})
	Delay = AutoVoidDrop:CreateSlider({
		Name = 'Delay',
		Min = 0,
		Max = 2,
		Decimal = 100,
		Default = 0.1,
		Suffix = 's'
	})
end)

